async (params, browser) => {
  // Open CoinMarketCap homepage
  await browser.open('https://coinmarketcap.com/')

  // Wait for rankings table to load
  await browser.waitForSelector('table tbody tr', 15000)

  // Let table data render
  await browser.wait(2500)

  // Scroll to load more rows
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further for more coins
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Extract coin rankings
  const rankings_data = await browser.evaluate(`const limit = parseInt('' + params.limit + '') || 20; const coins = []; const rows = document.querySelectorAll('table tbody tr'); for (let i = 0; i < Math.min(rows.length, limit); i++) { const row = rows[i]; const cells = row.querySelectorAll('td'); if (cells.length < 7) continue; const rank = cells[1] ? cells[1].textContent.trim() : String(i + 1); const nameCell = cells[2]; const linkEl = nameCell ? nameCell.querySelector('a[href*="/currencies/"]') : null; const allPs = nameCell ? nameCell.querySelectorAll('p') : []; let name = ''; let symbol = ''; if (allPs.length >= 2) { name = allPs[0].textContent.trim(); symbol = allPs[1].textContent.trim(); } else if (linkEl) { const parts = linkEl.textContent.trim().split(/\s+/); name = parts[0] || ''; symbol = parts[1] || ''; } else if (nameCell) { const parts = nameCell.textContent.trim().split(/\n/).map(function(s) { return s.trim(); }).filter(Boolean); name = parts[0] || ''; symbol = parts[1] || ''; } const priceCell = cells[3]; const price = priceCell ? priceCell.textContent.trim() : ''; const change1hCell = cells[4]; const change1h = change1hCell ? change1hCell.textContent.trim() : ''; const change24hCell = cells[5]; const change24h = change24hCell ? change24hCell.textContent.trim() : ''; const change7dCell = cells[6]; const change7d = change7dCell ? change7dCell.textContent.trim() : ''; const marketCapCell = cells[7]; const marketCap = marketCapCell ? marketCapCell.textContent.trim() : ''; const volumeCell = cells[8]; const volume = volumeCell ? volumeCell.textContent.trim() : ''; coins.push({ rank: rank, name: name, symbol: symbol, price: price, change_1h: change1h, change_24h: change24h, change_7d: change7d, market_cap: marketCap, volume_24h: volume, url: linkEl ? linkEl.href : '' }); } return { scraped_count: coins.length, coins: coins }`)

  return rankings_data
}
